 1	import React, { FC, Ref, useState } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import SriovNetworkNodePolicyModel from '@kubevirt-ui/kubevirt-api/console/models/SriovNetworkNodePolicyModel';
 5	import {
 6	  getGroupVersionKindForModel,
 7	  K8sResourceKind,
 8	  useK8sWatchResource,
 9	} from '@openshift-console/dynamic-plugin-sdk';
10	import {
11	  Dropdown,
12	  DropdownItem,
13	  DropdownList,
14	  FormGroup,
15	  MenuToggle,
16	  MenuToggleElement,
17	  TextArea,
18	  TextInput,
19	} from '@patternfly/react-core';
20	import PopoverHelpIcon from '@utils/components/PopoverHelpIcon/PopoverHelpIcon';
21	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
22	import {
23	  NetworkAttachmentDefinitionFormInput,
24	  NetworkTypeKeys,
25	} from '@views/nads/form/utils/types';
26	
27	const SriovParameters: FC = () => {
28	  const { t } = useNetworkingTranslation();
29	  const { control, register } = useFormContext<NetworkAttachmentDefinitionFormInput>();
30	  const [isDropdownOpen, setIsDropdownOpen] = useState<boolean>(false);
31	
32	  const [sriovNetNodePoliciesData] = useK8sWatchResource<K8sResourceKind[]>({
33	    groupVersionKind: getGroupVersionKindForModel(SriovNetworkNodePolicyModel),
34	    isList: true,
35	    optional: true,
36	  });
37	
38	  return (
39	    <>
40	      <FormGroup isRequired label={t('Resource name')}>
41	        <Controller
42	          control={control}
43	          name={`${NetworkTypeKeys.sriovNetworkType}.resourceName`}
44	          render={({ field: { onChange, value } }) => (
45	            <Dropdown
46	              id="resource-name"
47	              isOpen={isDropdownOpen}
48	              onSelect={() => setIsDropdownOpen(false)}
49	              selected={value}
50	              toggle={(toggleRef: Ref<MenuToggleElement>) => (
51	                <MenuToggle
52	                  id="toggle-nads-network-type"
53	                  isExpanded={isDropdownOpen}
54	                  isFullWidth
55	                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
56	                  ref={toggleRef}
57	                >
58	                  {value || t('Select resource name')}
59	                </MenuToggle>
60	              )}
61	            >
62	              <DropdownList>
63	                {sriovNetNodePoliciesData.map((policy) => {
64	                  const policyName = policy?.spec?.resourceName;
65	                  return (
66	                    <DropdownItem
67	                      key={policyName}
68	                      onClick={() => {
69	                        onChange(policyName);
70	                      }}
71	                      value={policyName}
72	                    >
73	                      {policyName}
74	                    </DropdownItem>
75	                  );
76	                })}
77	              </DropdownList>
78	            </Dropdown>
79	          )}
80	          rules={{ required: true }}
81	        />
82	      </FormGroup>
83	      <FormGroup label={t('IP address management')}>
84	        <TextArea {...register(`${NetworkTypeKeys.sriovNetworkType}.ipam`)} />
85	      </FormGroup>
86	      <FormGroup
87	        label={t('VLAN tag number')}
88	        labelHelp={<PopoverHelpIcon bodyContent={t('Example: 100')} />}
89	      >
90	        <TextInput {...register(`${NetworkTypeKeys.sriovNetworkType}.vlanTagNum`)} />
91	      </FormGroup>
92	    </>
93	  );
94	};
95	
96	export default SriovParameters;

